self.addEventListener("push",i=>{try{let n=i.data?i.data.json():{},t=n.title||"Vichar Bhandar",e=n.body||"You have a new reminder.";i.waitUntil(self.registration.showNotification(t,{body:e,icon:"/favicon.ico",badge:"/favicon.ico"}))}catch(i){console.error("Error showing push notification:",i)}}),self.addEventListener("notificationclick",i=>{i.notification.close(),i.waitUntil(self.clients.matchAll({type:"window"}).then(i=>{for(let n of i)if("/"===n.url&&"focus"in n)return n.focus();if(self.clients.openWindow)return self.clients.openWindow("/")}))});